import{_ as o,o as t,c as e,ag as r}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"典型例题与解析","description":"","frontmatter":{},"headers":[],"relativePath":"notes/gaozhong/gaoyi/chapter01-sets/examples.md","filePath":"notes/gaozhong/gaoyi/chapter01-sets/examples.md"}'),$={name:"notes/gaozhong/gaoyi/chapter01-sets/examples.md"};function l(n,a,p,i,s,h){return t(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="典型例题与解析" tabindex="-1">典型例题与解析 <a class="header-anchor" href="#典型例题与解析" aria-label="Permalink to &quot;典型例题与解析&quot;">​</a></h1><blockquote><p>以下例题涵盖集合各知识点的典型考法，适合巩固练习。</p></blockquote><hr><h2 id="一、集合的概念与表示" tabindex="-1">一、集合的概念与表示 <a class="header-anchor" href="#一、集合的概念与表示" aria-label="Permalink to &quot;一、集合的概念与表示&quot;">​</a></h2><h3 id="例题-1" tabindex="-1">例题 1 <a class="header-anchor" href="#例题-1" aria-label="Permalink to &quot;例题 1&quot;">​</a></h3><blockquote><p>判断下列对象能否组成集合，并说明理由： （1）小于 5 的自然数；（2）所有偶数；（3）比较聪明的人</p></blockquote><p><strong>解析：</strong></p><p>（1）能组成集合——每个自然数是否小于 5 是确定的。</p><p>（2）能组成集合——所有偶数是一个确定的无限集合。</p><p>（3）不能组成集合——&quot;比较聪明&quot;没有确定的标准，因人而异，不满足集合的<strong>确定性</strong>。</p><hr><h3 id="例题-2" tabindex="-1">例题 2 <a class="header-anchor" href="#例题-2" aria-label="Permalink to &quot;例题 2&quot;">​</a></h3><blockquote><p>用适当的方法表示&quot;绝对值小于 3 的整数&quot;。</p></blockquote><p><strong>解析：</strong></p><p>列举法：${-2, -1, 0, 1, 2}$</p><p>描述法：${x \\in \\mathbb{Z} \\mid |x| &lt; 3}$</p><hr><h2 id="二、集合间的关系" tabindex="-1">二、集合间的关系 <a class="header-anchor" href="#二、集合间的关系" aria-label="Permalink to &quot;二、集合间的关系&quot;">​</a></h2><h3 id="例题-3" tabindex="-1">例题 3 <a class="header-anchor" href="#例题-3" aria-label="Permalink to &quot;例题 3&quot;">​</a></h3><blockquote><p>设 $A = {x \\mid x^2 - 5x + 6 = 0}$，$B = {2, 3}$，判断 $A$ 与 $B$ 的关系。</p></blockquote><p><strong>解析：</strong></p><p>$A = {2, 3}$（方程 $x^2 - 5x + 6 = 0$ 的根为 2 和 3）</p><p>$A$ 与 $B$ 的所有元素相同，所以 $A = B$，同时 $A \\subseteq B$ 且 $B \\subseteq A$。</p><hr><h3 id="例题-4" tabindex="-1">例题 4 <a class="header-anchor" href="#例题-4" aria-label="Permalink to &quot;例题 4&quot;">​</a></h3><blockquote><p>已知集合 $A$ 有 3 个元素，求 $A$ 的子集个数、真子集个数。</p></blockquote><p><strong>解析：</strong></p><p>子集个数：$2^3 = 8$</p><p>真子集个数：$2^3 - 1 = 7$（去掉自身）</p><hr><h2 id="三、集合的运算" tabindex="-1">三、集合的运算 <a class="header-anchor" href="#三、集合的运算" aria-label="Permalink to &quot;三、集合的运算&quot;">​</a></h2><h3 id="例题-5" tabindex="-1">例题 5 <a class="header-anchor" href="#例题-5" aria-label="Permalink to &quot;例题 5&quot;">​</a></h3><blockquote><p>设 $A = {1, 2, 3, 4}$，$B = {3, 4, 5, 6}$，求 $A \\cap B$，$A \\cup B$。</p></blockquote><p><strong>解析：</strong></p><p>$A \\cap B = {3, 4}$（两者共有的元素）</p><p>$A \\cup B = {1, 2, 3, 4, 5, 6}$（合并，去重）</p><hr><h3 id="例题-6" tabindex="-1">例题 6 <a class="header-anchor" href="#例题-6" aria-label="Permalink to &quot;例题 6&quot;">​</a></h3><blockquote><p>已知全集 $I = {0, 1, 2, 3, 4}$，$A = {1, 3}$，求 $\\complement_I A$。</p></blockquote><p><strong>解析：</strong></p><p>$\\complement_I A = {0, 2, 4}$（在全集 $I$ 中去掉 1 和 3）</p><hr><h3 id="例题-7" tabindex="-1">例题 7 <a class="header-anchor" href="#例题-7" aria-label="Permalink to &quot;例题 7&quot;">​</a></h3><blockquote><p>设 $A = {x \\mid x &gt; 1}$，$B = {x \\mid x \\leqslant 3}$，求 $A \\cap B$。</p></blockquote><p><strong>解析：</strong></p><p>$A \\cap B = {x \\mid 1 &lt; x \\leqslant 3}$，即区间 $(1, 3]$</p><hr><h2 id="四、综合应用" tabindex="-1">四、综合应用 <a class="header-anchor" href="#四、综合应用" aria-label="Permalink to &quot;四、综合应用&quot;">​</a></h2><h3 id="例题-8" tabindex="-1">例题 8 <a class="header-anchor" href="#例题-8" aria-label="Permalink to &quot;例题 8&quot;">​</a></h3><blockquote><p>某班有学生 45 人，其中喜欢足球的有 25 人，喜欢篮球的有 20 人，两项都喜欢的有 8 人。问：至少喜欢其中一项的有多少人？两项都不喜欢的有多少人？</p></blockquote><p><strong>解析：</strong></p><p>设 $A$ = 喜欢足球的学生，$B$ = 喜欢篮球的学生。</p><p>$|A| = 25$，$|B| = 20$，$|A \\cap B| = 8$</p><p>至少喜欢一项： $$|A \\cup B| = |A| + |B| - |A \\cap B| = 25 + 20 - 8 = 37 \\text{ 人}$$</p><p>两项都不喜欢： $$45 - 37 = 8 \\text{ 人}$$</p><hr><h3 id="例题-9-易错题" tabindex="-1">例题 9（易错题） <a class="header-anchor" href="#例题-9-易错题" aria-label="Permalink to &quot;例题 9（易错题）&quot;">​</a></h3><blockquote><p>设 $A = \\varnothing$，$B = {0}$，判断以下关系： （1）$A \\subseteq B$；（2）$A \\in B$；（3）$A = B$。</p></blockquote><p><strong>解析：</strong></p><p>（1）正确。空集是任何集合的子集，所以 $\\varnothing \\subseteq {0}$。</p><p>（2）错误。$B$ 的元素是 $0$，不是 $\\varnothing$，所以 $A \\notin B$。$A$ 与 $B$ 是<strong>集合与元素</strong>的关系，不能混淆。</p><p>（3）错误。$\\varnothing$ 不含任何元素，${0}$ 含有一个元素 $0$，两者不相等。</p><div class="warning custom-block"><p class="custom-block-title">易错提醒</p><ul><li>$\\subseteq$（子集）：用于集合与集合之间</li><li>$\\in$（属于）：用于元素与集合之间</li><li>$\\varnothing$（空集）≠ ${0}$（含有一个元素 0 的集合）</li></ul></div><hr><h3 id="例题-10-选做-—-含参数的集合问题" tabindex="-1">例题 10（选做 — 含参数的集合问题） <a class="header-anchor" href="#例题-10-选做-—-含参数的集合问题" aria-label="Permalink to &quot;例题 10（选做 — 含参数的集合问题）&quot;">​</a></h3><blockquote><p>已知集合 $A = {x \\in \\mathbb{R} \\mid ax - 2 = 0}$ 是单元素集，求实数 $a$ 的值。</p></blockquote><p><strong>解析：</strong></p><p>$A$ 是单元素集，即方程 $ax - 2 = 0$ 只有唯一解。</p><p>当 $a \\neq 0$ 时，$x = \\frac{2}{a}$，有唯一解，满足条件。</p><p>当 $a = 0$ 时，方程变为 $-2 = 0$，无解，$A = \\varnothing$（空集，不是单元素集）。</p><p>所以 $a \\neq 0$。</p><hr><h2 id="五、练习建议" tabindex="-1">五、练习建议 <a class="header-anchor" href="#五、练习建议" aria-label="Permalink to &quot;五、练习建议&quot;">​</a></h2><ol><li>先独立完成，再查看答案</li><li>重点关注<strong>例题 9</strong>的易错点（子集 vs 属于，空集 vs ${0}$）</li><li>尝试用 Venn 图理解<strong>例题 8</strong>的容斥原理</li><li>有余力可完成<strong>例题 10</strong>类型的含参问题</li></ol>',74)])])}const d=o($,[["render",l]]);export{u as __pageData,d as default};
